const item = $input.first();
const body = item.json.realEstateAds ?? item.json.body?.realEstateAds ?? item.json;
const ads = Array.isArray(body) ? body : (body.realEstateAds || []);
return ads.map(ad => ({
  json: {
    source: 'bienici',
    id_site: ad.id || '',
    titre: ad.title || '',
    description: (ad.description || '').replace(/<[^>]+>/g, ' ').trim().slice(0, 500),
    ville: ad.city || ad.district?.name || '',
    quartier: ad.district?.libelle || ad.district?.name || '',
    adresse: '',
    pieces: ad.roomsQuantity ?? null,
    surface_m2: ad.surfaceArea ?? null,
    loyer_cc: ad.price ?? null,
    charges: ad.charges ?? null,
    meuble: ad.isFurnished ?? null,
    url: `https://www.bienici.com/annonce/location/${(ad.city || '').toLowerCase().replace(/\s+/g, '-')}-${ad.postalCode || ''}/${ad.id || ''}`,
    date_publication: ad.publicationDate || null
  }
}));

const BASE = 'https://www.trente-cinq-notaires.fr';
const item = $input.first();
let html = item.json?.body ?? item.json?.data ?? (typeof item.json === 'string' ? item.json : '');
if (!html || typeof html !== 'string') return [];
const cardBlocks = html.split(/<div class="il-card-wrap">/).slice(1);
const out = [];
for (const block of cardBlocks) {
  if (!block.includes('il-card--LOCA') && !/il-card-transaction">\s*Location\s*</.test(block)) continue;
  const hrefMatch = block.match(/<a href="(\/recherche-annonces-immobilieres-notaires-bruz\/[^"]+\.html)"\s+class="reset-link">/);
  const path = hrefMatch ? hrefMatch[1] : '';
  const url = path ? BASE + path : '';
  const localeMatch = block.match(/il-card-locale">([^<]+)</);
  const locale = (localeMatch && localeMatch[1]) ? localeMatch[1].trim() : '';
  const idx = locale.lastIndexOf(' - ');
  const ville = (idx >= 0 ? locale.slice(0, idx) : locale).trim() || '';
  const priceMatch = block.match(/Loyer\s*:\s*([\d\s,]+)/);
  const loyerStr = priceMatch ? priceMatch[1].replace(/[^\d,]/g, '').replace(',', '.') : '';
  const loyer_cc = loyerStr ? parseFloat(loyerStr) : null;
  const refMatch = block.match(/Réf:\s*([\d\-]+)/);
  const id_site = (refMatch && refMatch[1]) ? refMatch[1].trim() : '';
  const surfaceMatch = block.match(/Intérieur[\s\S]*?<strong>\s*([\d,\.]+)\s*m²/);
  const surfaceStr = surfaceMatch ? surfaceMatch[1].replace(',', '.') : '';
  const surface_m2 = surfaceStr ? parseFloat(surfaceStr) : null;
  const piecesMatch = block.match(/<strong>(\d+)<\/strong>\s*<span>Pièces/);
  const pieces = piecesMatch ? parseInt(piecesMatch[1], 10) : null;
  const typeMatch = block.match(/il-card-type">([^<]+)</);
  const typeBien = (typeMatch && typeMatch[1]) ? typeMatch[1].trim() : '';
  let description = '';
  const excerptMatch = block.match(/il-card-excerpt">\s*([\s\S]*?)<\/p>/);
  if (excerptMatch && excerptMatch[1]) {
    description = excerptMatch[1].replace(/<small>[\s\S]*?<\/small>/, '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 500);
  }
  const titre = [typeBien, ville].filter(Boolean).join(' - ') || 'Annonce ' + id_site;
  out.push({
    json: {
      source: 'trentecinq',
      id_site,
      titre,
      description,
      ville,
      quartier: '',
      adresse: '',
      pieces,
      surface_m2,
      loyer_cc,
      charges: null,
      meuble: null,
      url,
      date_publication: null
    }
  });
}
return out;

const BASE_URL = 'https://logement-actionlogement.fr/search/detail/';
const item = $input.first();
const body = item.json?.data ?? item.json;
const data = Array.isArray(body) ? body : (body?.data || []);
const typoToPieces = { 'T1': 1, 'T2': 2, 'T3': 3, 'T4': 4, 'T5': 5 };
return data.map(o => {
  const lodg = o.lodging || {};
  const muni = lodg.municipality || {};
  const typo = lodg.lodgingTypology || {};
  const pieces = typoToPieces[typo.code] ?? null;
  const desc = (lodg.description || o.description || '').replace(/\s+/g, ' ').trim().slice(0, 500);
  return {
    json: {
      source: 'actionlogement',
      id_site: String(o.reference || o.id || ''),
      titre: [typo.commercialLabel || typo.label, muni.name].filter(Boolean).join(' - ') || 'Annonce ' + (o.reference || o.id),
      description: desc,
      ville: muni.name || '',
      quartier: (o.residency && o.residency.name) || '',
      adresse: (o.residency && o.residency.name) || '',
      pieces,
      surface_m2: lodg.area ?? null,
      loyer_cc: o.totalRentAmountBaseBound ?? null,
      charges: o.estimatedExternalCharges ?? null,
      meuble: null,
      url: o.guid ? BASE_URL + o.guid : '',
      date_publication: o.startDateOfPublication ?? null
    }
  };
});

const item = $input.first();
let html = item.json?.data ?? item.json?.body ?? (typeof item.json === 'string' ? item.json : '');
if (!html || typeof html !== 'string') return [];
const out = [];
const articleRegex = /<article class="card card--list-mobile"\s+entityid="(\d+)"[^>]*>([\s\S]*?)<\/article>/gi;
let m;
while ((m = articleRegex.exec(html)) !== null) {
  const id_site = (m[1] || '').trim();
  const block = m[2] || '';
  const hrefMatch = block.match(/<a href="(https?:\/\/[^"]+)"[^>]*class="card_title[^"]*"[^>]*>([^<]*)<\/a>/i);
  const url = (hrefMatch && hrefMatch[1]) ? hrefMatch[1].trim() : '';
  const titre = (hrefMatch && hrefMatch[2]) ? hrefMatch[2].trim() : '';
  const subtitleMatch = block.match(/<h3 class="card_subtitle">([^<]+)<\/h3>/);
  const villeRaw = (subtitleMatch && subtitleMatch[1]) ? subtitleMatch[1].trim() : '';
  const ville = villeRaw.replace(/\s*\(\s*\d+\s*\)\s*$/, '').trim();
  const priceMatch = block.match(/<h4 class="card_price">\s*([\d\s]+)\s*€/);
  const loyerStr = priceMatch ? priceMatch[1].replace(/\s/g, '') : '';
  const loyer_cc = loyerStr ? parseInt(loyerStr, 10) : null;
  const surfaceMatch = block.match(/card_info_item">[^<]*[\s\S]*?(\d+)\s*m2/);
  const surface_m2 = surfaceMatch ? parseInt(surfaceMatch[1], 10) : null;
  const piecesMatch = block.match(/card_info_item">[^<]*[\s\S]*?(\d+)\s*chambres/);
  const piecesRaw = piecesMatch ? parseInt(piecesMatch[1], 10) : null;
  const pieces = piecesRaw != null ? piecesRaw + 1 : null;
  const refMatch = block.match(/ref\.\s*([\d\-]+)/i);
  const ref = (refMatch && refMatch[1]) ? refMatch[1].trim() : id_site;
  out.push({
    json: {
      source: 'giboire',
      id_site: ref || id_site,
      titre: titre || 'Annonce ' + (ref || id_site),
      description: '',
      ville,
      quartier: '',
      adresse: '',
      pieces,
      surface_m2,
      loyer_cc,
      charges: null,
      meuble: null,
      url,
      date_publication: null
    }
  });
}
return out;

const BASE = 'https://www.afedim.fr';
function decodeHtml(str) {
  if (!str || typeof str !== 'string') return '';
  return str.replace(/&#(\d+);/g, (_, n) => String.fromCharCode(parseInt(n, 10)))
    .replace(/&#x([0-9a-f]+);/gi, (_, n) => String.fromCharCode(parseInt(n, 16)));
}
const item = $input.first();
let html = item.json?.data ?? item.json?.body ?? (typeof item.json === 'string' ? item.json : '');
if (!html || typeof html !== 'string') return [];
const out = [];
const cardBlocks = html.split(/<li class="item">/).slice(1);
for (const block of cardBlocks) {
  const titleMatch = block.match(/<p[^>]*class="ei_productcard__title"[^>]*>\s*<a[^>]+href="([^"]*)"[^>]*>([\s\S]*?)<\/a>/i) || block.match(/<a[^>]+href="([^"]*\/Fiche)"[^>]*>([\s\S]*?)<\/a>/i);
  const path = (titleMatch && titleMatch[1]) ? titleMatch[1].trim() : '';
  const url = path ? (path.startsWith('http') ? path : BASE + path) : '';
  let titre = (titleMatch && titleMatch[2]) ? titleMatch[2].replace(/\s+/g, ' ').trim() : '';
  titre = decodeHtml(titre);
  const idMatch = url.match(/\/(\d+)\/Fiche/);
  const id_site = (idMatch && idMatch[1]) ? idMatch[1] : '';
  const subtitleMatch = block.match(/<p class="ei_productcard__subtitle">([^<]+)<\/p>/);
  const ville = (subtitleMatch && subtitleMatch[1]) ? decodeHtml(subtitleMatch[1].trim()) : '';
  const priceMatch = block.match(/ei_blcdata_valtext[^>]*>([^<]+)</);
  const loyerStr = priceMatch ? priceMatch[1].replace(/\s/g, '').replace(',', '.') : '';
  const loyer_cc = loyerStr ? parseFloat(loyerStr) : null;
  const blockDecoded = decodeHtml(block);
  let surface_m2 = null;
  const surfaceNumMatch = blockDecoded.match(/([\d,]+)\s*m\s*²/i) || blockDecoded.match(/([\d,]+)\s*m2/i) || block.match(/([\d,]+)\s*m²/i) || block.match(/([\d,]+)\s*m\s*&#178;/i);
  if (surfaceNumMatch) {
    const surfaceStr = (surfaceNumMatch[1] || '').replace(',', '.');
    surface_m2 = surfaceStr ? parseFloat(surfaceStr) : null;
  }
  const piecesMatch = block.match(/(\d+)-pieces\/\d+\/Fiche/) || block.match(/href="[^"]*\/(\d+)-pieces\//) || titre.match(/(\d+)\s*pièces/);
  const pieces = piecesMatch ? parseInt(piecesMatch[1], 10) : null;
  out.push({
    json: {
      source: 'afedim',
      id_site: id_site || ('afedim_' + (url || '').slice(-8)),
      titre: titre || 'Annonce ' + id_site,
      description: '',
      ville,
      quartier: '',
      adresse: '',
      pieces,
      surface_m2,
      loyer_cc,
      charges: null,
      meuble: 'non',
      url,
      date_publication: null
    }
  });
}
const seen = new Set();
return out.filter(({ json }) => {
  const id = json.id_site;
  if (seen.has(id)) return false;
  seen.add(id);
  return true;
});

const allItems = [];
for (const item of $input.all()) {
  const j = item.json;
  const html = (j.data != null && typeof j.data === 'string') ? j.data : (j.body != null && typeof j.body === 'string') ? j.body : '';
  let source = j.source || '';
  if (html && !source) {
    if (/bienici\.com|bien'ici/i.test(html)) source = 'bienici';
    else if (/seloger/i.test(html)) source = 'seloger';
    else source = 'inconnu';
  }
  if (html && !j.titre && !j.loyer_cc && !j.surface_m2) {
    continue;
  }
  if (!j.titre && (j.loyer_cc == null || j.loyer_cc === 0) && (j.surface_m2 == null || j.surface_m2 === 0)) {
    continue;
  }
  allItems.push({
    json: {
      source: source || 'inconnu',
      id_site: j.id_site || '',
      titre: j.titre || '',
      description: j.description || '',
      ville: j.ville || '',
      quartier: j.quartier || '',
      adresse: j.adresse || '',
      pieces: j.pieces ?? null,
      surface_m2: j.surface_m2 ?? null,
      loyer_cc: j.loyer_cc ?? null,
      charges: j.charges ?? null,
      meuble: j.meuble ?? null,
      url: j.url || '',
      date_publication: j.date_publication ?? null
    }
  });
}
return allItems;

const cfg = $('Config critères (défaut)').first().json;
function normalizeVille(str) {
  return (str || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[̀-ͯ]/g, '')
    .replace(/-/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}
function matchVille(item) {
  const villeNorm = normalizeVille(item.ville);
  const contenu = ((item.quartier || '') + ' ' + (item.description || '') + ' ' + (item.titre || '')).toLowerCase();
  const villesCiblesNorm = JSON.parse(cfg.villes_cibles || '[]').map(v => normalizeVille(v));
  if (villesCiblesNorm.includes(villeNorm)) return true;
  if (villeNorm === normalizeVille(cfg.ville_speciale || '')) {
    const quartiersRennes = (cfg.quartiers_rennes_seulement || '').split(',').map(q => q.trim().toLowerCase()).filter(Boolean);
    return quartiersRennes.some(q => contenu.includes(q));
  }
  return false;
}
const output = [];
for (const item of $input.all()) {
  const a = item.json;
  const surface = Number(a.surface_m2 || 0);
  const prix = Number(a.loyer_cc || 0);
  const pieces = Number(a.pieces || 0);
  if (surface < cfg.surface_min_m2 || surface > cfg.surface_max_m2) continue;
  if (prix <= 0 || prix > cfg.prix_max_cc) continue;
  if (pieces < cfg.pieces_min || pieces > cfg.pieces_max) continue;
  if (!matchVille(a)) continue;
  output.push({ json: a });
}
return output;

function normalize(str) {
  return (str || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[^a-z0-9 ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}
const j = $input.item.json;
const keyBase = [
  normalize(j.ville),
  normalize(j.quartier),
  normalize(j.titre),
  String(j.surface_m2 || ''),
  String(j.loyer_cc || '')
].join('|');
let hash = 0;
for (let i = 0; i < keyBase.length; i++) {
  hash = ((hash << 5) - hash) + keyBase.charCodeAt(i);
  hash |= 0;
}
j.id_global = 'a_' + Math.abs(hash);
j._isAnnonce = true;
return { json: j };

const all = $input.all();
const annonces = all.filter(i => i.json._isAnnonce === true);
const sheetRows = all.filter(i => i.json._isAnnonce !== true);
function getId(row) {
  const j = row.json;
  const key = Object.keys(j).find(k => k.trim().toLowerCase() === 'id_global');
  return String(key ? j[key] : j.id_global || '').trim();
}
const existingIds = new Set(sheetRows.map(r => getId(r)));
let kept = annonces.filter(a => !existingIds.has(getId(a)));
const seenId = new Set();
kept = kept.filter(a => { const id = getId(a); if (seenId.has(id)) return false; seenId.add(id); return true; });
return kept.map(a => {
  const j = { ...a.json };
  delete j._isAnnonce;
  return { json: j };
});

